61тЖТasync def broadcast_ws():
62тЖТ    if not active_connections:
63тЖТ        return
64тЖТ    db = database.SessionLocal()
65тЖТ    try:
66тЖТ        machines = db.query(models.Machine).all()
67тЖТ        data = []
68тЖТ        for m in machines:
69тЖТ            remaining = max(0.0, m.initial_asnova_length - (m.current_total_meters - m.meters_at_fill))
70тЖТ            now = datetime.utcnow()
71тЖТ            is_esp_online = m.last_seen and (now - m.last_seen).total_seconds() < 60
72тЖТ            if not is_esp_online:
73тЖТ                status = "OFFLINE"
74тЖТ            elif m.current_baud == 0:
75тЖТ                status = "ESP_ONLINE_NO_SIGNAL"
76тЖТ            elif remaining <= 0:
77тЖТ                status = "ASNOVA_EMPTY"
78тЖТ            else:
79тЖТ                status = "RUNNING"
80тЖТ            data.append({
81тЖТ                "id": m.id, "status": status,
82тЖТ                "meters": round(m.current_total_meters, 2),
83тЖТ                "shift_meters": round(m.shift_meters, 2),
84тЖТ                "remaining": round(remaining, 2),
85тЖТ                "baud": m.current_baud, "protocol": m.current_protocol,
86тЖТ                "connection_source": m.connection_source,
87тЖТ                "preferred_source": m.preferred_source,
88тЖТ                "sys_info": {
89тЖТ                    "ram": {"free": m.esp_free_ram, "total": m.esp_total_ram},
90тЖТ                    "rom": {"free": m.esp_free_rom, "total": m.esp_total_rom},
91тЖТ                    "cpu": m.esp_cpu_freq,
92тЖТ                    "wifi": {"ssid": m.esp_wifi_ssid, "rssi": m.esp_wifi_rssi}
93тЖТ                }
94тЖТ            })
95тЖТ        msg = json.dumps(data)
96тЖТ        for ws in list(active_connections):
97тЖТ            try:
98тЖТ                await ws.send_text(msg)
99тЖТ            except:
100тЖТ                active_connections.remove(ws)
