1тЖТimport React, { useState } from 'react';
2тЖТimport axios from 'axios';
3тЖТimport { LogIn } from 'lucide-react';
4тЖТ
5тЖТconst API = `${window.location.protocol}//${window.location.host}`;
6тЖТ
7тЖТconst Login = ({ onLogin }) => {
8тЖТ  const [username, setUsername] = useState('');
9тЖТ  const [password, setPassword] = useState('');
10тЖТ  const [error, setError] = useState('');
11тЖТ  const [loading, setLoading] = useState(false);
12тЖТ
13тЖТ  const handleSubmit = async (e) => {
14тЖТ    e.preventDefault();
15тЖТ    setLoading(true);
16тЖТ    setError('');
17тЖТ    try {
18тЖТ      const response = await axios.post(`${API}/token`,
19тЖТ        new URLSearchParams({ username, password }),
20тЖТ        { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } }
21тЖТ      );
22тЖТ      const token = response.data.access_token;
23тЖТ      localStorage.setItem('token', token);
24тЖТ      
25тЖТ      const userResponse = await axios.get(`${API}/users/me`, {
26тЖТ        headers: { Authorization: `Bearer ${token}` }
27тЖТ      });
28тЖТ      onLogin(userResponse.data);
29тЖТ    } catch (err) {
30тЖТ      setError('Login yoki parol xato');
31тЖТ      setLoading(false);
32тЖТ    }
33тЖТ  };
34тЖТ
35тЖТ  return (
36тЖТ    <div className="login-page">
37тЖТ      <form onSubmit={handleSubmit} className="login-card">
38тЖТ        <div className="login-header">
39тЖТ          <div className="login-icon">
40тЖТ            <LogIn size={36} color="#38bdf8" />
41тЖТ          </div>
42тЖТ          <h2 className="login-title">SMART ESP32</h2>
43тЖТ          <p className="login-subtitle">Industrial Monitoring Portal</p>
44тЖТ        </div>
45тЖТ
46тЖТ        {error && <div className="login-error">{error}</div>}
47тЖТ
48тЖТ        <div className="login-field">
49тЖТ          <label>Foydalanuvchi</label>
50тЖТ          <input 
51тЖТ            type="text" 
52тЖТ            placeholder="Login kiriting"
53тЖТ            value={username} 
54тЖТ            onChange={(e) => setUsername(e.target.value)} 
55тЖТ            required 
56тЖТ            autoFocus
57тЖТ          />
58тЖТ        </div>
59тЖТ
60тЖТ        <div className="login-field">
61тЖТ          <label>Parol</label>
62тЖТ          <input 
63тЖТ            type="password" 
64тЖТ            placeholder="Parol kiriting"
65тЖТ            value={password} 
66тЖТ            onChange={(e) => setPassword(e.target.value)} 
67тЖТ            required 
68тЖТ          />
69тЖТ        </div>
70тЖТ
71тЖТ        <button type="submit" className="btn-submit login-btn" disabled={loading}>
72тЖТ          {loading ? 'Kutilmoqda...' : 'Kirish'}
73тЖТ        </button>
74тЖТ      </form>
75тЖТ    </div>
76тЖТ  );
77тЖТ};
78тЖТ
79тЖТexport default Login;
EOF
